44	library IEEE;
45	use IEEE.std_logic_1164.all;
46	use IEEE.numeric_std.all;
47	
48	use std.textio.all;
49	
50	-- library zpu;
51	
52	package psi_tb_txt_util is
53	   -- prints a message to the screen
54	   procedure print(text: string);
55	
56	   -- prints the message when active
57	   -- useful for debug switches
58	   procedure print(active: boolean; text: string);
59	
60	   -- converts std_logic into a character
61	   function chr(sl: std_logic) return character;
62	
63	   -- converts std_logic into a string (1 to 1)
64	   function str(sl: std_logic) return string;
65	
66	   -- converts std_logic_vector into a string (binary base)
67	   function str(slv: std_logic_vector) return string;
68	
69	   -- converts boolean into a string
70	   function str(b: boolean) return string;
71	
72	   -- converts an integer into a single character
73	   -- (can also be used for hex conversion and other bases)
74	   function chr(int: integer) return character;
75	
76	   -- converts integer into string using specified base
77	   function str(int: integer; base: integer) return string;
78	
79	   -- converts integer to string, using base 10
80	   function str(int: integer) return string;
81	
82	   -- convert std_logic_vector into a string in hex format
83	   function hstr(slv: std_logic_vector) return string;
84	   function hstr(slv: unsigned) return string;
85	   
86	   -- convert integer to string, VHDL2008 built-in equivalent
87	   function to_string(int : integer) return string;
88	
89	   -- convert real to string, VHDL2008 built-in equivalent
90	   function to_string(num : real) return string;
91	   
92	    -- convert signed to string, VHDL2008 built-in equivalent
93	   function to_string(num : signed) return string;
94	
95	   -- convert unsigned to string, VHDL2008 built-in equivalent
96	   function to_string(num : unsigned) return string;   
97	   
98	   -- convert std_logic_vector to string, VHDL2008 built-in equivalent
99	   function to_string(num : std_logic_vector) return string; 
100	
101	
102	   -- functions to manipulate strings
103	   -----------------------------------
104	
105	   -- convert a character to upper case
106	   function to_upper(c: character) return character;
107	
108	   -- convert a character to lower case
109	   function to_lower(c: character) return character;
110	
111	   -- convert a string to upper case
112	   function to_upper(s: string) return string;
113	
114	   -- convert a string to lower case
115	   function to_lower(s: string) return string;
116	
117	  
118	   
119	   -- functions to convert strings into other formats
120	   --------------------------------------------------
121	   
122	   -- converts a character into std_logic
123	   function to_std_logic(c: character) return std_logic; 
124	   
125	   -- converts a string into std_logic_vector
126	   function to_std_logic_vector(s: string) return std_logic_vector; 
127	
128	
129	 
130	   -- file I/O
131	   -----------
132	      
133	   -- read variable length string from input file
134	   procedure str_read(file in_file: TEXT; 
135	                      res_string: out string);
136	
137	   procedure str_write(file out_file: TEXT; 
138	                       new_string: in  string);
139	       
140	   -- print string to a file and start new line
141	   procedure print(file out_file: TEXT;
142	                   new_string: in  string);
143	   
144	   -- print character to a file and start new line
145	   procedure print(file out_file: TEXT;
146	                   char:       in  character);                   
147	end package psi_tb_txt_util;
