149	
150	
151	
152	package body psi_tb_txt_util is
153	   -- prints text to the screen
154	   procedure print(text: string) is
155	      variable msg_line: line;
156	   begin
157	      --synopsys translate off
158	      write(msg_line, text);
159	      writeline(output, msg_line);
160	      --synopsys translate on
161	   end procedure print;
162	
163	   -- prints text to the screen when active
164	   procedure print(active: boolean; text: string)  is
165	   begin
166	      if active then
167	         print(text);
168	      end if;
169	   end procedure print;
170	
171	   -- converts std_logic into a character
172	   function chr(sl: std_logic) return character is
173	      variable c: character;
174	   begin
175	      case sl is
176	           when 'U' => c:= 'U';
177	           when 'X' => c:= 'X';
178	           when '0' => c:= '0';
179	           when '1' => c:= '1';
180	           when 'Z' => c:= 'Z';
181	           when 'W' => c:= 'W';
182	           when 'L' => c:= 'L';
183	           when 'H' => c:= 'H';
184	           when '-' => c:= '-';
185	      end case;
186	      return c;
187	   end function chr;
188	
189	   -- converts std_logic into a string (1 to 1)
190	   function str(sl: std_logic) return string is
191	      variable s: string(1 to 1);
192	   begin
193	      s(1):=chr(sl);
194	      return s;
195	   end function str;
196	
197	   -- converts std_logic_vector into a string (binary base)
198	   -- (this also takes care of the fact that the range of
199	   --  a string is natural while a std_logic_vector may
200	   --  have an integer range)
201	   function str(slv: std_logic_vector) return string is
202	      variable result : string (1 to slv'length);
203	      variable r      : integer;
204	   begin
205	      r:=1;
206	      for i in slv'range loop
207	          result(r) := chr(slv(i));
208	          r:=r+1;
209	      end loop;
210	      return result;
211	   end function str;
212	
213	
214	   function str(b: boolean) return string is
215	   begin
216	      if b then
217	         return "true";
218	      else
219	         return "false";
220	      end if;
221	   end function str;
222	
223	   -- converts an integer into a character
224	   -- for 0 to 9 the obvious mapping is used, higher
225	   -- values are mapped to the characters A-Z
226	   -- (this is usefull for systems with base > 10)
227	   -- (adapted from Steve Vogwell's posting in comp.lang.vhdl)
228	   function chr(int: integer) return character is
229	      variable c: character;
230	   begin
231	      case int is
232	           when  0 => c := '0';
233	           when  1 => c := '1';
234	           when  2 => c := '2';
235	           when  3 => c := '3';
236	           when  4 => c := '4';
237	           when  5 => c := '5';
238	           when  6 => c := '6';
239	           when  7 => c := '7';
240	           when  8 => c := '8';
241	           when  9 => c := '9';
242	           when 10 => c := 'A';
243	           when 11 => c := 'B';
244	           when 12 => c := 'C';
245	           when 13 => c := 'D';
246	           when 14 => c := 'E';
247	           when 15 => c := 'F';
248	           when 16 => c := 'G';
249	           when 17 => c := 'H';
250	           when 18 => c := 'I';
251	           when 19 => c := 'J';
252	           when 20 => c := 'K';
253	           when 21 => c := 'L';
254	           when 22 => c := 'M';
255	           when 23 => c := 'N';
256	           when 24 => c := 'O';
257	           when 25 => c := 'P';
258	           when 26 => c := 'Q';
259	           when 27 => c := 'R';
260	           when 28 => c := 'S';
261	           when 29 => c := 'T';
262	           when 30 => c := 'U';
263	           when 31 => c := 'V';
264	           when 32 => c := 'W';
265	           when 33 => c := 'X';
266	           when 34 => c := 'Y';
267	           when 35 => c := 'Z';
268	           when others => c := '?';
269	      end case;
270	      return c;
271	   end function chr;
272	
273	   -- convert integer to string using specified base
274	   -- (adapted from Steve Vogwell's posting in comp.lang.vhdl)
275	   function str(int: integer; base: integer) return string is
276	      variable temp    : string(1 to 10);
277	      variable num     : integer;
278	      variable abs_int : integer;
279	      variable len     : integer:=1;
280	      variable power   : integer:=1;
281	   begin
282	      -- bug fix for negative numbers
283	      abs_int:=abs(int);
284	  
285	      num    :=abs_int;
286	  
287	      while num>=base loop                       -- Determine how many
288	         len:=len+1;                             -- characters required
289	         num:=num/base;                          -- to represent the
290	      end loop;                                  -- number.
291	  
292	      for i in len downto 1 loop                 -- Convert the number to
293	          temp(i):=chr(abs_int/power mod base);  -- a string starting
294	          power:=power*base;                     -- with the right hand
295	      end loop ;                                 -- side.
296	  
297	      -- return result and add sign if required
298	      if int<0 then
299	         return '-'& temp(1 to len);
300	      else
301	         return temp(1 to len);
302	      end if;
303	   end function str;
304	
305	   -- convert integer to string, using base 10
306	   function str(int: integer) return string is
307	   begin
308	      return str(int, 10) ;
309	   end function str;
310	
311	   -- converts a std_logic_vector into a hex string.
312	   function hstr(slv: std_logic_vector) return string is
313	      variable hexlen: integer;
314	      variable longslv : std_logic_vector(67 downto 0):=(others => '0');
315	      variable hex : string(1 to 16);
316	      variable fourbit : std_logic_vector(3 downto 0);
317	   begin
318	      hexlen:=(slv'left+1)/4;
319	      if (slv'left+1) mod 4/=0 then
320	         hexlen := hexlen + 1;
321	      end if;
322	      longslv(slv'left downto 0) := slv;
323	      for i in (hexlen-1) downto 0 loop
324	          fourbit:=longslv(((i*4)+3) downto (i*4));
325	          case fourbit is
326	               when "0000" => hex(hexlen-I):='0';
327	               when "0001" => hex(hexlen-I):='1';
328	               when "0010" => hex(hexlen-I):='2';
329	               when "0011" => hex(hexlen-I):='3';
330	               when "0100" => hex(hexlen-I):='4';
331	               when "0101" => hex(hexlen-I):='5';
332	               when "0110" => hex(hexlen-I):='6';
333	               when "0111" => hex(hexlen-I):='7';
334	               when "1000" => hex(hexlen-I):='8';
335	               when "1001" => hex(hexlen-I):='9';
336	               when "1010" => hex(hexlen-I):='A';
337	               when "1011" => hex(hexlen-I):='B';
338	               when "1100" => hex(hexlen-I):='C';
339	               when "1101" => hex(hexlen-I):='D';
340	               when "1110" => hex(hexlen-I):='E';
341	               when "1111" => hex(hexlen-I):='F';
342	               when "ZZZZ" => hex(hexlen-I):='z';
343	               when "UUUU" => hex(hexlen-I):='u';
344	               when "XXXX" => hex(hexlen-I):='x';
345	               when others => hex(hexlen-I):='?';
346	          end case;
347	      end loop;
348	      return hex(1 to hexlen);
349	   end function hstr;
350	
351	   function hstr(slv: unsigned) return string is
352	   begin
353	      return hstr(std_logic_vector(slv));
354	   end function hstr;
355	   
356	   -- VHDL2008 to_string built-in equivalents
357	   function to_string(int : integer) return string is
358	   begin
359	      return str(int);
360	   end function;
361	   
362	   function to_string(num : real) return string is
363	   begin
364	      return real'image(num);
365	   end function;
366	
367	   function to_string(num : signed) return string is
368	   begin
369	      return integer'image(to_integer(num));
370	   end function;
371	   
372	   function to_string(num : unsigned) return string is
373	   begin
374	      return integer'image(to_integer(num));
375	   end function;
376	   
377	   function to_string(num : std_logic_vector) return string is
378	   begin
379	      return str(num);
380	   end function;   
381	
382	   -- functions to manipulate strings
383	   -----------------------------------
384	
385	
386	   -- convert a character to upper case
387	   function to_upper(c: character) return character is
388	      variable u: character;
389	   begin
390	      case c is
391	           when 'a' => u:='A';
392	           when 'b' => u:='B';
393	           when 'c' => u:='C';
394	           when 'd' => u:='D';
395	           when 'e' => u:='E';
396	           when 'f' => u:='F';
397	           when 'g' => u:='G';
398	           when 'h' => u:='H';
399	           when 'i' => u:='I';
400	           when 'j' => u:='J';
401	           when 'k' => u:='K';
402	           when 'l' => u:='L';
403	           when 'm' => u:='M';
404	           when 'n' => u:='N';
405	           when 'o' => u:='O';
406	           when 'p' => u:='P';
407	           when 'q' => u:='Q';
408	           when 'r' => u:='R';
409	           when 's' => u:='S';
410	           when 't' => u:='T';
411	           when 'u' => u:='U';
412	           when 'v' => u:='V';
413	           when 'w' => u:='W';
414	           when 'x' => u:='X';
415	           when 'y' => u:='Y';
416	           when 'z' => u:='Z';
417	           when others => u:=c;
418	      end case;
419	      return u;
420	   end function to_upper;
421	
422	
423	   -- convert a character to lower case
424	   function to_lower(c: character) return character is
425	      variable l: character;
426	   begin
427	      case c is
428	           when 'A' => l:='a';
429	           when 'B' => l:='b';
430	           when 'C' => l:='c';
431	           when 'D' => l:='d';
432	           when 'E' => l:='e';
433	           when 'F' => l:='f';
434	           when 'G' => l:='g';
435	           when 'H' => l:='h';
436	           when 'I' => l:='i';
437	           when 'J' => l:='j';
438	           when 'K' => l:='k';
439	           when 'L' => l:='l';
440	           when 'M' => l:='m';
441	           when 'N' => l:='n';
442	           when 'O' => l:='o';
443	           when 'P' => l:='p';
444	           when 'Q' => l:='q';
445	           when 'R' => l:='r';
446	           when 'S' => l:='s';
447	           when 'T' => l:='t';
448	           when 'U' => l:='u';
449	           when 'V' => l:='v';
450	           when 'W' => l:='w';
451	           when 'X' => l:='x';
452	           when 'Y' => l:='y';
453	           when 'Z' => l:='z';
454	           when others => l:=c;
455	      end case;
456	      return l;
457	   end function to_lower;
458	
459	   -- convert a string to upper case
460	   function to_upper(s: string) return string is
461	      variable uppercase: string (s'range);
462	   begin
463	      for i in s'range loop
464	          uppercase(i):=to_upper(s(i));
465	      end loop;
466	      return uppercase;
467	   end to_upper;
468	
469	   -- convert a string to lower case
470	   function to_lower(s: string) return string is
471	      variable lowercase: string (s'range);
472	   begin
473	      for i in s'range loop
474	          lowercase(i):=to_lower(s(i));
475	      end loop;
476	      return lowercase;
477	   end to_lower;
478	
479	   -- functions to convert strings into other types
480	   
481	   -- converts a character into a std_logic
482	   
483	   function to_std_logic(c: character) return std_logic is
484	      variable sl : std_logic;
485	   begin
486	      case c is
487	           when 'U' =>
488	                sl:='U';
489	           when 'X' =>
490	                sl:='X';
491	           when '0' => 
492	                sl:='0';
493	           when '1' => 
494	                sl:='1';
495	           when 'Z' => 
496	                sl:='Z';
497	           when 'W' => 
498	                sl:='W';
499	           when 'L' => 
500	                sl:='L';
501	           when 'H' => 
502	                sl:='H';
503	           when '-' => 
504	                sl:='-';
505	           when others =>
506	                sl:='X';
507	      end case;
508	      return sl;
509	   end function to_std_logic;
510	   
511	   
512	   -- converts a string into std_logic_vector
513	   function to_std_logic_vector(s: string) return std_logic_vector is 
514	      variable slv : std_logic_vector(s'high-s'low downto 0);
515	      variable k   : integer;
516	   begin
517	      k:=s'high-s'low;
518	      for i in s'range loop
519	          slv(k):=to_std_logic(s(i));
520	          k     :=k-1;
521	      end loop;
522	      return slv;
523	   end function to_std_logic_vector;
524	                                       
525	                                       
526	   ----------------
527	   --  file I/O  --
528	   ----------------
529	   
530	   -- read variable length string from input file
531	   procedure str_read(file in_file: TEXT; 
532	                      res_string: out string) is
533	      variable l         : line;
534	      variable c         : character;
535	      variable is_string : boolean;
536	   begin
537	      readline(in_file, l);
538	      -- clear the contents of the result string
539	      for i in res_string'range loop
540	          res_string(i):=' ';
541	      end loop;   
542	      -- read all characters of the line, up to the length  
543	      -- of the results string
544	      for i in res_string'range loop
545	          read(l,c,is_string);
546	          res_string(i):=c;
547	          if not is_string then -- found end of line
548	             exit;
549	          end if;
550	      end loop; 
551	   end procedure str_read;
552	   
553	   -- print string to a file
554	   procedure print(file out_file: TEXT;
555	                   new_string: in  string) is
556	      variable l: line;
557	   begin
558	      write(l,new_string);
559	      writeline(out_file,l);
560	   end procedure print;
561	   
562	   -- print character to a file and start new line
563	   procedure print(file out_file: TEXT;
564	                   char: in  character) is
565	      variable l: line;
566	   begin
567	      write(l,char);
568	      writeline(out_file,l);
569	   end procedure print;
570	   
571	   -- appends contents of a string to a file until line feed occurs
572	   -- (LF is considered to be the end of the string)
573	   procedure str_write(file out_file: TEXT; 
574	                       new_string: in  string) is
575	   begin
576	      for i in new_string'range loop
577	          print(out_file,new_string(i));
578	          if new_string(i)=LF then -- end of string
579	             exit;
580	          end if;
581	      end loop;               
582	   end str_write;
583	end package body psi_tb_txt_util;
